{
  "name": "scrumpoker",
  "version": "1.0.0",
  "description": "Real-time scrum poker for remote teams",
  "type": "module",
  "main": "server.js",
  "scripts": {
    "start": "node server.js",
    "dev": "node --watch server.js"
  },
  "dependencies": {
    "express": "^4.19.2",
    "socket.io": "^4.7.5",
    "uuid": "^9.0.1"
  }
}

import { createServer } from "node:http";
import { randomUUID } from "node:crypto";
import { dirname, join } from "node:path";
import { fileURLToPath } from "node:url";
import express from "express";
import { Server } from "socket.io";

const __dirname = dirname(fileURLToPath(import.meta.url));
const app = express();
const httpServer = createServer(app);
const io = new Server(httpServer);

const PORT = process.env.PORT || 3000;

// In-memory store: roomId → { users: Map<socketId, { name, vote }>, revealed: boolean }
const rooms = new Map();

function getOrCreateRoom(roomId) {
  if (!rooms.has(roomId)) {
    rooms.set(roomId, { users: new Map(), revealed: false });
  }
  return rooms.get(roomId);
}

function getRoomPayload(room) {
  return {
    users: Array.from(room.users.entries()).map(([id, u]) => ({
      id,
      name: u.name,
      vote: room.revealed ? u.vote : u.vote !== null ? "hidden" : null,
    })),
    revealed: room.revealed,
  };
}

app.use(express.static(join(__dirname, "public")));

// Serve room page for any /room/:id route
app.get("/room/:id", (_req, res) => {
  res.sendFile(join(__dirname, "public", "room.html"));
});

// Create a new room and redirect
app.get("/create", (_req, res) => {
  const id = randomUUID();
  res.redirect(`/room/${id}`);
});

io.on("connection", (socket) => {
  let currentRoom = null;

  socket.on("join-room", ({ roomId, name }) => {
    if (!roomId || !name) return;

    // Sanitise inputs
    const safeRoomId = String(roomId).slice(0, 64);
    const safeName = String(name).trim().slice(0, 32) || "Anonymous";

    const room = getOrCreateRoom(safeRoomId);
    room.users.set(socket.id, { name: safeName, vote: null });
    currentRoom = safeRoomId;

    socket.join(safeRoomId);
    io.to(safeRoomId).emit("room-update", getRoomPayload(room));
  });

  socket.on("vote", ({ roomId, vote }) => {
    const room = rooms.get(roomId);
    if (!room) return;
    const user = room.users.get(socket.id);
    if (!user) return;
    if (room.revealed) return; // no voting after reveal

    const VALID_VOTES = [0, 0.5, 1, 2, 3, 5, 8, 13, "?", 9999];
    if (!VALID_VOTES.includes(vote)) return;

    user.vote = vote;
    io.to(roomId).emit("room-update", getRoomPayload(room));
  });

  socket.on("show-votes", ({ roomId }) => {
    const room = rooms.get(roomId);
    if (!room) return;
    room.revealed = true;
    io.to(roomId).emit("room-update", getRoomPayload(room));
  });

  socket.on("reset-votes", ({ roomId }) => {
    const room = rooms.get(roomId);
    if (!room) return;
    for (const user of room.users.values()) {
      user.vote = null;
    }
    room.revealed = false;
    io.to(roomId).emit("room-update", getRoomPayload(room));
  });

  socket.on("disconnect", () => {
    if (!currentRoom) return;
    const room = rooms.get(currentRoom);
    if (!room) return;

    room.users.delete(socket.id);

    if (room.users.size === 0) {
      rooms.delete(currentRoom);
    } else {
      io.to(currentRoom).emit("room-update", getRoomPayload(room));
    }
  });
});

httpServer.listen(PORT, () => {
  console.log(`Scrum Poker running at http://localhost:${PORT}`);
});

/* ── Reset & base ── */
*, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }

:root {
  --bg: #0f1117;
  --surface: #1a1d27;
  --surface2: #22263a;
  --border: #2e3250;
  --primary: #6c63ff;
  --primary-hover: #574fd6;
  --secondary: #3a3f5c;
  --secondary-hover: #4a5070;
  --text: #e8eaf0;
  --text-muted: #8b90a8;
  --card-back: #22263a;
  --card-selected: #6c63ff;
  --card-revealed: #1e3a5f;
  --green: #4caf76;
  --radius: 10px;
  --shadow: 0 4px 24px rgba(0,0,0,0.4);
}

body {
  font-family: 'Segoe UI', system-ui, sans-serif;
  background: var(--bg);
  color: var(--text);
  min-height: 100vh;
}

/* ── Landing ── */
.landing {
  display: flex;
  align-items: center;
  justify-content: center;
}

.landing-card {
  background: var(--surface);
  border: 1px solid var(--border);
  border-radius: var(--radius);
  padding: 3rem 4rem;
  text-align: center;
  box-shadow: var(--shadow);
  max-width: 480px;
  width: 90%;
}

.landing-card h1 { font-size: 2.2rem; margin-bottom: 1rem; }
.landing-card p  { color: var(--text-muted); margin-bottom: 2rem; line-height: 1.6; }

/* ── Buttons ── */
.btn {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  gap: 0.4rem;
  padding: 0.6rem 1.4rem;
  border: none;
  border-radius: 8px;
  font-size: 0.95rem;
  font-weight: 600;
  cursor: pointer;
  transition: background 0.15s, transform 0.1s;
  text-decoration: none;
}
.btn:active { transform: scale(0.97); }

.btn-primary   { background: var(--primary);   color: #fff; }
.btn-primary:hover { background: var(--primary-hover); }

.btn-secondary { background: var(--secondary); color: var(--text); }
.btn-secondary:hover { background: var(--secondary-hover); }

.btn-ghost {
  background: transparent;
  color: var(--text-muted);
  border: 1px solid var(--border);
  font-size: 0.8rem;
  padding: 0.3rem 0.8rem;
}
.btn-ghost:hover { background: var(--surface2); color: var(--text); }

.btn-large { padding: 0.85rem 2.4rem; font-size: 1.1rem; }

/* ── Modal ── */
.modal-overlay {
  position: fixed; inset: 0;
  background: rgba(0,0,0,0.7);
  display: flex; align-items: center; justify-content: center;
  z-index: 100;
}
.modal-overlay.hidden { display: none; }

.modal-card {
  background: var(--surface);
  border: 1px solid var(--border);
  border-radius: var(--radius);
  padding: 2.5rem;
  width: 90%; max-width: 400px;
  box-shadow: var(--shadow);
}
.modal-card h2 { margin-bottom: 0.5rem; }
.modal-card p  { color: var(--text-muted); margin-bottom: 1.5rem; }

#name-form {
  display: flex;
  gap: 0.75rem;
}
#name-input {
  flex: 1;
  padding: 0.6rem 1rem;
  background: var(--surface2);
  border: 1px solid var(--border);
  border-radius: 8px;
  color: var(--text);
  font-size: 1rem;
  outline: none;
}
#name-input:focus { border-color: var(--primary); }

/* ── Room layout ── */
.hidden { display: none !important; }

.room-header {
  display: flex;
  align-items: center;
  justify-content: space-between;
  flex-wrap: wrap;
  gap: 0.75rem;
  padding: 1rem 2rem;
  background: var(--surface);
  border-bottom: 1px solid var(--border);
}
.room-header h1 { font-size: 1.4rem; }
.room-id {
  display: flex;
  align-items: center;
  gap: 0.5rem;
  color: var(--text-muted);
  font-size: 0.85rem;
}
.room-id span {
  font-family: monospace;
  color: var(--text);
  font-size: 0.8rem;
}

.room-main {
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 2.5rem;
  padding: 2.5rem 1.5rem;
  max-width: 860px;
  margin: 0 auto;
}

/* ── Players ── */
.players-section, .vote-section, .controls {
  width: 100%;
}

.players-section h2,
.vote-section h2 {
  font-size: 1rem;
  text-transform: uppercase;
  letter-spacing: 0.08em;
  color: var(--text-muted);
  margin-bottom: 1rem;
}

.player-list {
  display: flex;
  flex-wrap: wrap;
  gap: 0.75rem;
  list-style: none;
}

.player-item {
  background: var(--surface);
  border: 1px solid var(--border);
  border-radius: var(--radius);
  padding: 0.75rem 1.2rem;
  display: flex;
  align-items: center;
  gap: 0.75rem;
  min-width: 160px;
  transition: border-color 0.2s;
}

.player-item.voted { border-color: var(--green); }

.player-avatar {
  width: 36px; height: 36px;
  border-radius: 50%;
  background: var(--primary);
  display: flex; align-items: center; justify-content: center;
  font-weight: 700;
  font-size: 0.95rem;
  flex-shrink: 0;
}

.player-info { display: flex; flex-direction: column; }
.player-name { font-weight: 600; font-size: 0.95rem; }
.player-vote {
  font-size: 0.8rem;
  color: var(--text-muted);
  margin-top: 0.1rem;
}
.player-vote.revealed { color: var(--green); font-weight: 700; }
.player-vote.hidden-vote::before { content: "✓ voted"; color: var(--green); }
.player-vote.waiting::before { content: "waiting…"; }

.player-item.you .player-name::after {
  content: " (you)";
  color: var(--text-muted);
  font-weight: 400;
  font-size: 0.8rem;
}

/* ── Vote cards ── */
.card-deck {
  display: flex;
  flex-wrap: wrap;
  gap: 0.75rem;
}

.vote-card {
  width: 64px; height: 90px;
  border-radius: 10px;
  background: var(--card-back);
  border: 2px solid var(--border);
  display: flex; align-items: center; justify-content: center;
  font-size: 1.1rem;
  font-weight: 700;
  cursor: pointer;
  transition: border-color 0.15s, background 0.15s, transform 0.1s;
  user-select: none;
}
.vote-card:hover { border-color: var(--primary); background: var(--surface2); transform: translateY(-3px); }
.vote-card.selected { background: var(--card-selected); border-color: var(--card-selected); color: #fff; transform: translateY(-5px); }
.vote-card:active { transform: translateY(0); }

/* ── Controls ── */
.controls {
  display: flex;
  gap: 1rem;
  flex-wrap: wrap;
}

/* ── Responsive ── */
@media (max-width: 500px) {
  .room-header { padding: 0.75rem 1rem; }
  .room-main { padding: 1.5rem 1rem; }
  .vote-card { width: 54px; height: 76px; font-size: 1rem; }
}

const VOTE_OPTIONS = [0, 0.5, 1, 2, 3, 5, 8, 13, "?", 9999];

const roomId = location.pathname.split("/room/")[1];
if (!roomId) location.href = "/";

// ── DOM refs ──────────────────────────────────────────────────────────────
const nameModal       = document.getElementById("name-modal");
const nameForm        = document.getElementById("name-form");
const nameInput       = document.getElementById("name-input");
const app             = document.getElementById("app");
const roomIdDisplay   = document.getElementById("room-id-display");
const copyBtn         = document.getElementById("copy-btn");
const playerList      = document.getElementById("player-list");
const cardDeck        = document.getElementById("card-deck");
const showBtn         = document.getElementById("show-btn");
const resetBtn        = document.getElementById("reset-btn");

// ── State ─────────────────────────────────────────────────────────────────
let mySocketId  = null;
let myVote      = null;
let roomRevealed = false;

// ── Socket ────────────────────────────────────────────────────────────────
const socket = io();

socket.on("connect", () => {
  mySocketId = socket.id;
});

socket.on("room-update", (room) => {
  roomRevealed = room.revealed;
  renderPlayers(room.users);
  renderDeck(room.revealed);
  showBtn.disabled  = room.revealed;
  showBtn.textContent = room.revealed ? "Votes Revealed" : "Show Votes";
});

// ── Name form ─────────────────────────────────────────────────────────────
nameForm.addEventListener("submit", (e) => {
  e.preventDefault();
  const name = nameInput.value.trim();
  if (!name) return;

  socket.emit("join-room", { roomId, name });
  nameModal.classList.add("hidden");
  app.classList.remove("hidden");
  roomIdDisplay.textContent = roomId.slice(0, 8) + "…";
});

// ── Copy link ─────────────────────────────────────────────────────────────
copyBtn.addEventListener("click", () => {
  navigator.clipboard.writeText(location.href).then(() => {
    const orig = copyBtn.textContent;
    copyBtn.textContent = "✅ Copied!";
    setTimeout(() => { copyBtn.textContent = orig; }, 1500);
  });
});

// ── Build card deck ───────────────────────────────────────────────────────
VOTE_OPTIONS.forEach((val) => {
  const card = document.createElement("button");
  card.className = "vote-card";
  card.textContent = val;
  card.dataset.value = val;

  card.addEventListener("click", () => {
    if (roomRevealed) return;
    // Toggle off if already selected
    if (myVote === val) return;
    myVote = val;
    socket.emit("vote", { roomId, vote: val });
    updateSelectedCard(val);
  });

  cardDeck.appendChild(card);
});

function updateSelectedCard(val) {
  document.querySelectorAll(".vote-card").forEach((c) => {
    // eslint-disable-next-line eqeqeq -- intentional loose equality for string/number comparison
    c.classList.toggle("selected", c.dataset.value == val);
  });
}

// ── Controls ──────────────────────────────────────────────────────────────
showBtn.addEventListener("click", () => {
  socket.emit("show-votes", { roomId });
});

resetBtn.addEventListener("click", () => {
  myVote = null;
  updateSelectedCard(null);
  socket.emit("reset-votes", { roomId });
});

// ── Render ────────────────────────────────────────────────────────────────
function renderPlayers(users) {
  playerList.innerHTML = "";

  for (const user of users) {
    const isMe = user.id === mySocketId;
    const hasVoted = user.vote !== null;

    const li = document.createElement("li");
    li.className = `player-item${hasVoted ? " voted" : ""}${isMe ? " you" : ""}`;

    const initials = user.name
      .split(" ")
      .map((w) => w[0]?.toUpperCase() ?? "")
      .slice(0, 2)
      .join("");

    let voteDisplay = "";
    if (roomRevealed && hasVoted) {
      voteDisplay = `<span class="player-vote revealed">${user.vote}</span>`;
    } else if (hasVoted) {
      voteDisplay = `<span class="player-vote hidden-vote"></span>`;
    } else {
      voteDisplay = `<span class="player-vote waiting"></span>`;
    }

    li.innerHTML = `
      <div class="player-avatar">${initials || "?"}</div>
      <div class="player-info">
        <span class="player-name">${escapeHtml(user.name)}</span>
        ${voteDisplay}
      </div>`;

    playerList.appendChild(li);
  }
}

function renderDeck(revealed) {
  document.querySelectorAll(".vote-card").forEach((c) => {
    c.disabled = revealed;
    c.style.opacity = revealed ? "0.5" : "1";
    c.style.cursor  = revealed ? "not-allowed" : "pointer";
  });
}

function escapeHtml(str) {
  return str.replace(/[&<>"']/g, (ch) =>
    ({ "&": "&amp;", "<": "&lt;", ">": "&gt;", '"': "&quot;", "'": "&#39;" })[ch]
  );
}

